/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications. Currently focused
 * on email settings; additional channels can be added later.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': send as events occur
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Notification category — groups related notification types.
 * Maps to the prefix of NotificationType (e.g. 'order' covers
 * 'order:confirmation' and 'order:status-update').
 */
export type NotificationCategory = 'order' | 'user';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master toggle for all email notifications. */
  enabled: boolean;
  /** Delivery frequency for non-urgent emails. */
  frequency: EmailFrequency;
  /** Categories the user wants to receive. */
  subscribedCategories: NotificationCategory[];
}

/**
 * A user's full notification preferences.
 */
export interface UserNotificationPreferences {
  userId: string;
  email: EmailPreferences;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields are optional —
 * only provided fields are updated.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationCategory[];
}

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: ['order', 'user'],
};

/**
 * Extract the category from a notification type.
 * e.g. 'order:confirmation' -> 'order'
 */
export function getCategoryFromType(type: NotificationType): NotificationCategory {
  return type.split(':')[0] as NotificationCategory;
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Stores preferences in-memory (matching the project's existing data layer
 * approach). Returns default preferences for users who haven't customized
 * their settings.
 */

import type {
  UserNotificationPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  getCategoryFromType,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get notification preferences for a user.
   * Returns default preferences if the user hasn't customized them.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return existing;
    }

    return {
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      updatedAt: new Date(),
    };
  }

  /**
   * Update email notification preferences for a user.
   * Merges provided fields with existing preferences.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      userId,
      email: {
        enabled: input.enabled ?? current.email.enabled,
        frequency: input.frequency ?? current.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...current.email.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated email preferences for user ${userId}`);

    return updated;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if the user has email enabled and is subscribed to
   * the notification's category.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.email.enabled) {
      return false;
    }

    if (prefs.email.frequency === 'none') {
      return false;
    }

    const category = getCategoryFromType(notificationType);
    return prefs.email.subscribedCategories.includes(category);
  }

  /**
   * Delete stored preferences for a user (reverts to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existed = this.preferences.has(userId);
    this.preferences.delete(userId);
    if (existed) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return existed;
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

